import{_ as e,o as t,c as o,ae as l}from"./chunks/framework.C7FLYIpo.js";const w=JSON.parse('{"title":"게이트웨이 잠금","description":"WebSocket 리스너 바인딩을 사용하는 게이트웨이 싱글톤 가드","frontmatter":{"title":"게이트웨이 잠금","description":"WebSocket 리스너 바인딩을 사용하는 게이트웨이 싱글톤 가드"},"headers":[],"relativePath":"gateway/gateway-lock.md","filePath":"gateway/gateway-lock.md","lastUpdated":null}'),i={name:"gateway/gateway-lock.md"};function r(c,a,n,d,s,h){return t(),o("div",null,[...a[0]||(a[0]=[l('<h1 id="게이트웨이-잠금" tabindex="-1">게이트웨이 잠금 <a class="header-anchor" href="#게이트웨이-잠금" aria-label="Permalink to &quot;게이트웨이 잠금&quot;">​</a></h1><h2 id="이유" tabindex="-1">이유 <a class="header-anchor" href="#이유" aria-label="Permalink to &quot;이유&quot;">​</a></h2><ul><li>동일 호스트의 기본 포트당 하나의 게이트웨이 인스턴스만 실행되도록 보장합니다; 추가 게이트웨이는 격리된 프로필과 고유한 포트를 사용해야 합니다.</li><li>오래된 잠금 파일을 남기지 않고 충돌/SIGKILL에서 살아남습니다.</li><li>컨트롤 포트가 이미 점유된 경우 명확한 오류와 함께 빠르게 실패합니다.</li></ul><h2 id="메커니즘" tabindex="-1">메커니즘 <a class="header-anchor" href="#메커니즘" aria-label="Permalink to &quot;메커니즘&quot;">​</a></h2><ul><li>게이트웨이는 시작 시 즉시 전용 TCP 리스너를 사용하여 WebSocket 리스너(기본 <code>ws://127.0.0.1:18789</code>)를 바인딩합니다.</li><li>바인딩이 <code>EADDRINUSE</code>로 실패하면 시작이 <code>GatewayLockError(&quot;another gateway instance is already listening on ws://127.0.0.1:&lt;port&gt;&quot;)</code>를 발생시킵니다.</li><li>OS는 충돌 및 SIGKILL을 포함한 모든 프로세스 종료 시 리스너를 자동으로 해제합니다—별도의 잠금 파일이나 정리 단계가 필요 없습니다.</li><li>종료 시 게이트웨이는 WebSocket 서버와 기본 HTTP 서버를 닫아 포트를 즉시 해제합니다.</li></ul><h2 id="오류-표면" tabindex="-1">오류 표면 <a class="header-anchor" href="#오류-표면" aria-label="Permalink to &quot;오류 표면&quot;">​</a></h2><ul><li>다른 프로세스가 포트를 보유하고 있으면 시작이 <code>GatewayLockError(&quot;another gateway instance is already listening on ws://127.0.0.1:&lt;port&gt;&quot;)</code>를 발생시킵니다.</li><li>다른 바인딩 실패는 <code>GatewayLockError(&quot;failed to bind gateway socket on ws://127.0.0.1:&lt;port&gt;: …&quot;)</code>로 표면화됩니다.</li></ul><h2 id="운영-참고-사항" tabindex="-1">운영 참고 사항 <a class="header-anchor" href="#운영-참고-사항" aria-label="Permalink to &quot;운영 참고 사항&quot;">​</a></h2><ul><li>포트가 <em>다른</em> 프로세스에 의해 점유된 경우 오류는 동일합니다; 포트를 해제하거나 <code>openclaw gateway --port &lt;port&gt;</code>로 다른 포트를 선택하십시오.</li><li>macOS 앱은 게이트웨이를 생성하기 전에 자체 경량 PID 가드를 여전히 유지합니다; 런타임 잠금은 WebSocket 바인딩에 의해 적용됩니다.</li></ul><h2 id="관련-항목" tabindex="-1">관련 항목 <a class="header-anchor" href="#관련-항목" aria-label="Permalink to &quot;관련 항목&quot;">​</a></h2><ul><li><a href="/openclaw-docs-ko/gateway/multiple-gateways">멀티 게이트웨이</a> — 고유한 포트로 여러 인스턴스 실행</li><li><a href="/openclaw-docs-ko/gateway/troubleshooting">문제 해결</a> — <code>EADDRINUSE</code> 및 포트 충돌 진단</li></ul>',11)])])}const k=e(i,[["render",r]]);export{w as __pageData,k as default};
